29	@Injectable()
30	export class RelatedProductsService {
31		private readonly logger = new Logger(RelatedProductsService.name);
32	
33		constructor(
34			private readonly algoliaService: AlgoliaService,
35			private readonly colorMatchWorkerService: ColorMatchWorkerService,
36			private readonly styleAlternativesService: StyleAlternativesService,
37			private readonly metricsService: MetricsService,
38			private readonly productHydrationService: ProductHydrationService,
39			private readonly styleColorsService: StyleColorsService,
40			private readonly stylesService: StylesService,
41		) {}
