43		private async getCurrentColorStyle(
44			styleId: number,
45			colorId?: number,
46		): Promise<IStyleColorBase | null> {
47			if (colorId) {
48				const styleByColor = await this.styleColorsService.getStyleByStyleAndColorId({
49					styleId,
50					colorId,
51				});
52				if (styleByColor) {
53					return styleByColor;
54				}
55			}
56	
57			const style = await this.styleColorsService.getStyleByStyleId({ styleId });
58			if (!style) {
59				this.logger.warn('No style found', { styleId });
60			}
61			return style;
62		}
63	
64		private async applyColorMatching(
65			products: IRelatedProduct[],
66			mvRecords: Map<number, IStylesMvBase>,
67			currentStyleColor: IStyleColorBase,
68		): Promise<IRelatedProduct[]> {
69			const colorCache = new Map<
70				number,
71				ReturnType<typeof this.productHydrationService.convertMvColorsToProductColors>
72			>();
73	
74			return Promise.all(
75				products.map(async (product) => {
76					const mv = mvRecords.get(product.style_id);
77					let colors = colorCache.get(product.style_id);
78					if (!colors) {
79						colors = this.productHydrationService.convertMvColorsToProductColors({
80							colors: mv?.colors ?? null,
81						});
82						colorCache.set(product.style_id, colors);
83					}
84					if (colors.length > 0) {
85						const closestColorId = await this.colorMatchWorkerService.findClosestColorId({
86							color: currentStyleColor,
87							palette: colors,
88						});
89						const closestColor = colors.find((c) => c.id === closestColorId);
90						if (closestColor) {
91							return {
92								...product,
93								color: closestColorId,
94								image_src: closestColor.image_url ?? product.image_src,
95							};
96						}
97					}
98					return product;
99				}),
100			);
101		}
