103		async getRelatedProducts({
104			productId,
105			query,
106		}: {
107			productId: string;
108			query: RelatedProductsQueryDto;
109		}): Promise<RelatedProductsResponseDto> {
110			if (!productId || productId.trim() === '') {
111				this.logger.error('Product ID is required to fetch related products');
112				throw new BadRequestException('Product ID is required');
113			}
114	
115			const numericProductId = Number(productId);
116			if (!Number.isInteger(numericProductId) || numericProductId <= 0) {
117				this.logger.error(`Invalid Product ID format: ${productId}`);
118				throw new BadRequestException(
119					`Product ID must be a valid positive integer, received: ${productId}`,
120				);
121			}
122	
123			const { limit, colorId } = query;
124	
125			try {
126				const styleIds = await this.algoliaService.getRelatedProductIds({
127					productId: numericProductId,
128				});
129				this.logger.debug('[getRelatedProducts] Algolia returned related IDs', {
130					count: styleIds.length,
131				});
132	
133				if (styleIds.length === 0) {
134					throw new NotFoundException(
135						`No related products found for product ID: ${productId}`,
136					);
137				}
138	
139				const [currentStyleColor, { products, mvRecords }] = await Promise.all([
140					this.getCurrentColorStyle(numericProductId, colorId),
141					this.productHydrationService.hydrateProductsWithColors({
142						styleIds,
143					}),
144				]);
145	
146				const relatedProducts = currentStyleColor
147					? await this.applyColorMatching(products, mvRecords, currentStyleColor)
148					: products;
149				this.logger.debug('[getRelatedProducts] Hydration complete', {
150					hydratedCount: relatedProducts.length,
151				});
152	
153				if (relatedProducts.length === 0) {
154					throw new NotFoundException(
155						`No related products found for product ID: ${productId}`,
156					);
157				}
158	
159				return {
160					product_id: productId,
161					related_products: relatedProducts.slice(0, limit),
162					color_id: colorId ?? null,
163				};
164			} catch (error: unknown) {
165				const err = error instanceof Error ? error : new Error(String(error));
166				this.logger.error(
167					`Error fetching related products from Algolia for productId ${productId}, colorId ${colorId}: ${err.message}`,
168					err.stack,
169				);
170	
171				await this.metricsService.incrementDailyCounter({
172					metricType: dailyTrackingKeys.MMS_REQUESTS,
173				});
174	
175				const [alternativeStyleIds, currentStyleColor] = await Promise.all([
176					this.styleAlternativesService.getAlternativeStyleIds({
177						styleId: numericProductId,
178					}),
179					this.getCurrentColorStyle(numericProductId, colorId),
180				]);
181				this.logger.debug('[getRelatedProducts] DB alternatives fetched', {
182					count: alternativeStyleIds.length,
183				});
184	
185				if (alternativeStyleIds.length === 0) {
186					this.logger.warn(`No DB alternatives found for product ID: ${productId}`);
187					return {
188						product_id: productId,
189						related_products: [],
190						mms_fallback: true,
191						color_id: colorId ?? null,
192					};
193				}
194	
195				const alternatives = await this.productHydrationService.hydrateProducts({
196					styleIds: alternativeStyleIds,
197					currentStyleColor,
198					activeOnly: true,
199				});
200	
201				this.logger.log('[getRelatedProducts] Fallback completed', {
202					productId,
203					fallbackCount: Math.min(alternatives.length, limit ?? alternatives.length),
204				});
205	
206				return {
207					product_id: productId,
208					related_products: alternatives.slice(0, limit),
209					mms_fallback: true,
210					color_id: colorId ?? null,
211				};
212			}
213		}
