215		async getBrandProducts({
216			brand,
217			limit,
218			colorId,
219			styleId,
220			sortBy,
221		}: BrandProductsQueryDto): Promise<BrandProductsResponseDto> {
222			this.logger.debug('[getBrandProducts] Starting brand products fetch', {
223				brand,
224				styleId,
225				colorId,
226				sortBy,
227				limit,
228			});
229	
230			try {
231				const shouldFetchColor = Boolean(colorId && styleId);
232	
233				const productLimit = limit ?? 30;
234	
235				const [{ products, mvRecords }, currentStyleColor] = await Promise.all([
236					this.productHydrationService.getProductsByBrands({
237						brands: [brand],
238						limit: productLimit,
239					}),
240					shouldFetchColor
241						? this.styleColorsService.getStyleByStyleAndColorId({
242								styleId: Number(styleId),
243								colorId: Number(colorId),
244							})
245						: Promise.resolve(null),
246				]);
247				this.logger.debug('[getBrandProducts] Brand products fetched', {
248					count: products.length,
249				});
250	
251				if (products.length === 0) {
252					throw new NotFoundException(`No products found for brand: ${brand}`);
253				}
254	
255				const productsWithColor = currentStyleColor
256					? await (async () => {
257							const colorCache = new Map<
258								number,
259								ReturnType<
260									typeof this.productHydrationService.convertMvColorsToProductColors
261								>
262							>();
263							return Promise.all(
264								products.map(async (product) => {
265									const mv = mvRecords.get(product.style_id);
266									let colors = colorCache.get(product.style_id);
267									if (!colors) {
268										colors = this.productHydrationService.convertMvColorsToProductColors({
269											colors: mv?.colors ?? null,
270										});
271										colorCache.set(product.style_id, colors);
272									}
273									if (colors.length > 0 && currentStyleColor) {
274										const closestColorId =
275											await this.colorMatchWorkerService.findClosestColorId({
276												color: currentStyleColor,
277												palette: colors,
278											});
279										const closestColor = colors.find((c) => c.id === closestColorId);
280										if (closestColor) {
281											return {
282												...product,
283												color: closestColorId,
284												image_src: closestColor.image_url ?? product.image_src,
285											};
286										}
287									}
288									return product;
289								}),
290							);
291						})()
292					: products;
293	
294				let finalProducts = productsWithColor;
295	
296				if (sortBy) {
297					this.logger.debug('[getBrandProducts] Applying sort', { sortBy });
298					let currentStyleCategoryId: number | null = null;
299					if (sortBy === 'category' && styleId) {
300						const currentStyle = await this.stylesService.getStyleById({
301							styleId: Number(styleId),
302						});
303						currentStyleCategoryId = currentStyle?.primary_category_id ?? null;
304					}
305					finalProducts = sortStyles({
306						products: productsWithColor,
307						sortBy,
308						currentStyleCategoryId,
309					});
310				}
311	
312				return {
313					product_id: styleId?.toString() ?? '',
314					brand_products: finalProducts.slice(0, limit),
315					color_id: colorId ?? null,
316					brand,
317					sort_by: sortBy ?? null,
318				};
319			} catch (error: unknown) {
320				const err = error instanceof Error ? error : new Error(String(error));
321				this.logger.error(
322					`Failed to get products for brand ${brand}, styleId ${styleId}: ${err.message}`,
323					err.stack,
324				);
325	
326				throw err;
327			}
328		}
329	}
