import {
	BadRequestException,
	Injectable,
	Logger,
	NotFoundException,
} from '@nestjs/common';

import { AlgoliaService } from '@modules/algolia/algolia.service';
import { ColorMatchWorkerService } from '@modules/color-match-worker/color-match-worker.service';
import { StyleAlternativesService } from '@modules/db/style-alternatives/style-alternatives.service';
import { StyleColorsService } from '@modules/db/style-colors/style-colors.service';
import { IStyleColorBase } from '@modules/db/style-colors/types/style-color.base.interface';
import { StylesService } from '@modules/db/styles/styles.service';
import { IStylesMvBase } from '@modules/db/styles-mv/types/styles-mv.base.interface';
import { MetricsService } from '@modules/metrics/metrics.service';
import { ProductHydrationService } from '@modules/product-hydration/product-hydration.service';

import { sortStyles } from '@utils/sort-styles.utils';

import { dailyTrackingKeys } from '@constants/common.constant';

import { IRelatedProduct } from '@interfaces/related-product.interface';

import { BrandProductsQueryDto } from '@dto/brand-products/brand-products-query.dto';
import { BrandProductsResponseDto } from '@dto/brand-products/brand-products-response.dto';
import { RelatedProductsQueryDto } from '@dto/related-products/related-products-query.dto';
import { RelatedProductsResponseDto } from '@dto/related-products/related-products-response.dto';

@Injectable()
export class RelatedProductsService {
	private readonly logger = new Logger(RelatedProductsService.name);

	constructor(
		private readonly algoliaService: AlgoliaService,
		private readonly colorMatchWorkerService: ColorMatchWorkerService,
		private readonly styleAlternativesService: StyleAlternativesService,
